import{WilsonsAlgorithm}from"./class.min.js";import{DownloadButton,GenerateButton}from"/scripts/components/buttons.min.js";import{Checkbox}from"/scripts/components/checkboxes.min.js";import{TextBox}from"/scripts/components/textBoxes.min.js";import{$}from"/scripts/src/main.min.js";export default function(){const e=new WilsonsAlgorithm({canvas:$("#output-canvas")}),n=new TextBox({element:$("#grid-size-input"),name:"Grid Size",value:50,minValue:5,maxValue:200,onEnter:r}),o=(new GenerateButton({element:$("#generate-button"),onClick:r}),new DownloadButton({element:$("#download-button"),applet:e,filename:()=>"wilsons-algorithm.png"}),new Checkbox({element:$("#animate-maze-checkbox"),name:"Animate drawing maze",checked:!0})),t=new Checkbox({element:$("#animate-coloring-checkbox"),name:"Animate coloring",checked:!0}),a=new Checkbox({element:$("#draw-borders-checkbox"),name:"Draw borders",checked:!0});function r(){e.run({gridSize:n.value,animateMaze:o.checked,animateColoring:t.checked,noBorders:!a.checked})}e.run({gridSize:n.value,animateMaze:!1,animateColoring:!1,noBorders:!a.checked})}